Use ASP.NET Core's `WebApplicationFactory<T>` to create an in-memory test server, then point an MCP client at it via the factory's `HttpClient`:

```csharp
// Install packages:
// Microsoft.AspNetCore.Mvc.Testing
// ModelContextProtocol (or your MCP client library)

using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly WebApplicationFactory<Program> _factory;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _factory = factory;
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var client = _factory.CreateClient();

        // Send MCP initialize request
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await client.PostAsJsonAsync("/mcp", request);
        response.EnsureSuccessStatusCode();

        var result = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", result.GetProperty("jsonrpc").GetString());
        Assert.True(result.TryGetProperty("result", out var res));
        Assert.True(res.TryGetProperty("serverInfo", out _));
    }

    [Fact]
    public async Task ToolCall_ExecutesAndReturnsResult()
    {
        var client = _factory.CreateClient();

        // Initialize first, then call a tool
        // ... (initialize as above) ...

        var toolCall = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await client.PostAsJsonAsync("/mcp", toolCall);
        response.EnsureSuccessStatusCode();

        var result = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.False(result.TryGetProperty("error", out _));
    }
}
```

**Key points:**

- **No real server** — `WebApplicationFactory` hosts your app in-process with a test `HttpClient` that talks directly to the middleware pipeline.
- **Full protocol fidelity** — requests traverse routing, middleware, serialization, and your MCP handlers exactly as in production.
- **For SSE/streaming endpoints**, use `HttpCompletionOption.ResponseHeadersRead` and read the stream incrementally.
- **Customize DI** by overriding `WebApplicationFactory.ConfigureWebHost` to swap in test doubles for external dependencies.

If you're using the official `ModelContextProtocol` C# SDK, you can also create an `SseClientTransport` with a custom `HttpClient`:

```csharp
var httpClient = _factory.CreateClient();
var transport = new SseClientTransport(
    new Uri("http://localhost/mcp/sse"),
    httpClient);
var mcpClient = await McpClientFactory.CreateAsync(transport);

var tools = await mcpClient.ListToolsAsync();
Assert.NotEmpty(tools);
```

This gives you a typed MCP client exercising the real protocol without any network.
